                </div>
                <div className="px-4 py-2 rounded-xl bg-[#FDE047]/10 text-sm font-semibold">
                  ⏱ {questions.reduce((a, q) => a + (q.timeLimit || 0), 0)}s {lang === "ENG" ? "total" : "total"}
