import {
  ArrowLeft, Wallet2, QrCode, Keyboard, ArrowRight, Users, Trophy, Clock, CheckCircle2, XCircle, Gift, LogOut, ExternalLink, Loader2
} from "lucide-react";
import confetti from "canvas-confetti";
import Link from "next/link";
