  const nextQuestion = () => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(i => i + 1);
      setSelectedAnswer(null);
      setIsCorrect(null);
      setTimeLeft(questions[currentQuestionIndex + 1].time_limit_seconds || 15);
      setQuizState("playing");
