                const walletStr = publicKey.toString();
                try {
                  await supabase.from("profiles").upsert(
                    { wallet_address: walletStr, username: playerName },
                    { onConflict: 'wallet_address' }
                  );
                  await supabase.from("leaderboard").upsert({
                    quiz_id: quizData.id,
                    user_wallet: walletStr,
